css:
.top {
    direction: rtl;
    display: flex;
    justify-content: space-between;
    align-items: flex-start;
    width: 100%;
    gap: 10px;
}

.top-left {
    flex: 0 0 60%;
    max-width: 60%;
}
.top-right-head{
direction: ltr;
}
.top-right {

    text-align: justify;
    flex: 0 0 40%;
    max-width: 40%;
    text-align: right;
    display: flex;
    align-items: flex-start;
    flex-direction: column;
    gap: 8px;   /* ← controls vertical spacing */
}
.totals {
    direction: rtl;
    display: flex;
    justify-content: space-between;
    align-items: flex-end;
    width: 100%;
    gap: 10px;
    margin-top: 10%;
}

.totals-left {
    flex: 0 0 70%;
    max-width: 70%;
}

.totals-right {
    flex: 0 0 30%;
    max-width: 30%;
    text-align: right;
    display: flex;
    align-items: flex-start;
    flex-direction: column;
    gap: 8px;   /* ← controls vertical spacing */
}
.title-p {
    font-weight: bold;
    color: gray;

}
.items-table {
    direction: rtl;
    width: 100%;
    border-collapse: collapse;
    font-size: 11px;
}

.items-table th,.items-table td {
    border: none !important;
    padding: 6px 4px;
    vertical-align: middle;
}

.items-table thead th {
    font-weight: bold;
}

.text-right {
    text-align: right;
}

.text-center {
    text-align: center;
}
.section-divider {
    border-top: 1px solid #ccc;

}
.double-line-section {

}

.double-line-section .line {
    height: 1px;
    background: #f2f2f2;   /* change to #ccc if you want lighter */
    margin: 5px 0;
}

.due-amount {
    margin: 4px 0;
    font-size: 12px;
}
.due-highlight {
    background-color: #f2f2f2;   /* soft grey */
    padding: 6px 8px;
    margin-top: 6px;
    border-radius: 4px;          /* subtle modern touch */
    font-weight: bold;
}
.description{
    direction: rtl;
       color: gray;
       margin-top:20px;
}
.description-text{
    direction: rtl;

}
.dotted-line {
    border-top: 2px dotted #000000;
    margin: 10px 0;
    width:50%;
}
.top-right-discription{
    display: flex;
    justify-content: flex-end;
    flex-direction: column;
    align-items: flex-end;
}
.main-title {
    text-align: center;
    margin-bottom: 15px;
}

.part-title {
    text-align: center;
    margin: 12px 0;
}

.section {
    margin-bottom: 15px;
}

.section-title {
    font-weight: bold;
    border-bottom: 1px solid #ccc;
    padding-bottom: 4px;
    margin-bottom: 6px;
}

.bilingual {
    display: flex;
    justify-content: space-between;
    gap: 20px;
}

.en {
    width: 50%;
    text-align: left;
}

.ar {
    width: 50%;
    text-align: right;
    direction: rtl;
}

ul {
    margin: 4px 0 8px 18px;
}

.ar ul {
    margin: 4px 18px 8px 0;
}

li {
    margin-bottom: 3px;
}

.acceptance {
    font-weight: bold;
    margin-top: 25px;
}
